"""Complete 294-parameter registry for the PwC Salesforce Org Health Check.

Each parameter has structured metadata: id, name, category key, data source,
SF CLI command, package dependency, description, scoring threshold, and
whether it can be auto-assessed.
"""

from __future__ import annotations

# ---------------------------------------------------------------------------
# Registry entry schema:
#   id            – "{category_num}.{param_num}" e.g. "2.1"
#   name          – Human-readable parameter name
#   category      – Key matching HEALTH_CATEGORIES (e.g. "code_quality")
#   data_source   – One of: code_analysis, tooling_api, runtime_soql,
#                   limits_api, limits_package, metadata, ai_inference, external
#   sf_cli_cmd    – The SF CLI command or Tooling API query used
#   package       – Package dependency (None or "Limit Monitor")
#   description   – What the parameter checks
#   threshold     – Scoring rules (PASS / WARN / FAIL)
#   assessable    – True if the tool can auto-assess; False for manual-review
#   scoring_key   – Internal key used by deterministic scorer to map data
# ---------------------------------------------------------------------------

