    # ======================================================================
    {"id": "8.1",  "name": "Active User Login Rate", "category": "ui_adoption", "data_source": "runtime_soql", "sf_cli_cmd": "SELECT COUNT(Id) FROM User WHERE LastLoginDate>LAST_N_DAYS:7 AND IsActive=true", "package": None, "description": "% of licensed users logging in at least weekly", "threshold": ">80% PASS, >60% WARN, <=60% FAIL", "assessable": True, "scoring_key": "active_users_7d"},
    {"id": "8.2",  "name": "License Utilization", "category": "ui_adoption", "data_source": "runtime_soql", "sf_cli_cmd": "SELECT Name, TotalLicenses, UsedLicenses FROM UserLicense WHERE TotalLicenses>0", "package": None, "description": "Active licenses vs. purchased licenses ratio", "threshold": ">80% used PASS, >50% WARN, <=50% FAIL", "assessable": True, "scoring_key": "license_utilization"},
    {"id": "8.3",  "name": "Inactive User Accounts", "category": "ui_adoption", "data_source": "runtime_soql", "sf_cli_cmd": "SELECT COUNT(Id) FROM User WHERE IsActive=true AND LastLoginDate<LAST_N_DAYS:90", "package": None, "description": "Users who haven't logged in for 90+ days", "threshold": "<5% PASS, <15% WARN, >=15% FAIL", "assessable": True, "scoring_key": "inactive_users_90d"},
    {"id": "8.4",  "name": "Login Frequency Distribution", "category": "ui_adoption", "data_source": "ai_inference", "sf_cli_cmd": "LoginHistory analysis by UserId", "package": None, "description": "Power users vs. occasional users distribution", "threshold": "AI assessment", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "8.5",  "name": "Page Layout Complexity", "category": "ui_adoption", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m Layout", "package": None, "description": "Fields per page layout; flag layouts with 50+ fields", "threshold": "AI assessment", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "8.6",  "name": "Page Layout Count per Object", "category": "ui_adoption", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m Layout, group by object", "package": None, "description": "Excessive layouts per object suggesting over-customization", "threshold": "<=5 PASS, <=10 WARN, >10 FAIL", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "8.7",  "name": "Lightning Page Performance", "category": "ui_adoption", "data_source": "tooling_api", "sf_cli_cmd": "SELECT DeveloperName, Type FROM FlexiPage", "package": None, "description": "Lightning page load times (FlexiPage component count)", "threshold": "<25 components PASS, <40 WARN, >=40 FAIL", "assessable": True, "scoring_key": "flexipage_components"},
    {"id": "8.8",  "name": "Visualforce Pages Still Active", "category": "ui_adoption", "data_source": "tooling_api", "sf_cli_cmd": "SELECT Name, ApiVersion FROM ApexPage", "package": None, "description": "Count of active VF pages (migration candidates for LWC)", "threshold": "0 PASS, <10 WARN, >=10 FAIL", "assessable": True, "scoring_key": "vf_pages_detail"},
    {"id": "8.9",  "name": "Aura Components Inventory", "category": "ui_adoption", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m AuraDefinitionBundle", "package": None, "description": "Aura components that should migrate to LWC", "threshold": "0 PASS, <10 WARN, >=10 FAIL", "assessable": True, "scoring_key": "metadata_auradefinitionbundle"},
    {"id": "8.10", "name": "LWC Component Count", "category": "ui_adoption", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m LightningComponentBundle", "package": None, "description": "Lightning Web Components in org", "threshold": "Present PASS, 0 WARN", "assessable": True, "scoring_key": "metadata_lightningcomponentbundle"},
    {"id": "8.11", "name": "Custom Tab Usage", "category": "ui_adoption", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m CustomTab", "package": None, "description": "Custom tabs created vs. actually used", "threshold": "AI assessment", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "8.12", "name": "Custom App Inventory", "category": "ui_adoption", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m CustomApplication", "package": None, "description": "Custom Lightning apps; check for unused/duplicate apps", "threshold": "<=10 PASS, <=20 WARN, >20 FAIL", "assessable": True, "scoring_key": "metadata_customapplication"},
    {"id": "8.13", "name": "Home Page Customization", "category": "ui_adoption", "data_source": "tooling_api", "sf_cli_cmd": "SELECT DeveloperName FROM FlexiPage WHERE Type='HomePage'", "package": None, "description": "Home page FlexiPages configured per profile/app", "threshold": "Configured PASS, default only WARN", "assessable": True, "scoring_key": "ai_inference"},
