    # ======================================================================
    # 9. TECHNICAL DEBT & ORG HYGIENE  (19 params, weight 6%)
    # ======================================================================
    {"id": "9.1",  "name": "Deprecated API Versions in Code", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT Name, ApiVersion FROM ApexClass WHERE ApiVersion<58 AND Status='Active'", "package": None, "description": "Apex classes/triggers on API versions 3+ releases behind", "threshold": "0 old PASS, <20% WARN, >=20% FAIL", "assessable": True, "scoring_key": "apex_class_api_version"},
    {"id": "9.2",  "name": "Unused Apex Classes", "category": "technical_debt", "data_source": "ai_inference", "sf_cli_cmd": "Cross-reference ApexCodeCoverage + MetadataComponentDependency", "package": None, "description": "Classes with no references or coverage (dead code)", "threshold": "0 unused PASS, <10% WARN, >=10% FAIL", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "9.3",  "name": "Unused Apex Triggers", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT Name FROM ApexTrigger WHERE Status!='Active'", "package": None, "description": "Disabled or orphaned triggers", "threshold": "0 unused PASS, any WARN", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "9.4",  "name": "Stale Validation Rules", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT ValidationName, LastModifiedDate FROM ValidationRule WHERE Active=true AND LastModifiedDate<LAST_N_DAYS:730", "package": None, "description": "Validation rules not modified in 2+ years", "threshold": "0 stale PASS, <10 WARN, >=10 FAIL", "assessable": True, "scoring_key": "validation_rules_stale"},
    {"id": "9.5",  "name": "Stale Workflow Rules", "category": "technical_debt", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m WorkflowRule", "package": None, "description": "Inactive or dormant Workflow Rules", "threshold": "0 stale PASS, <5 WARN, >=5 FAIL", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "9.6",  "name": "Unused Custom Labels", "category": "technical_debt", "data_source": "ai_inference", "sf_cli_cmd": "MetadataComponentDependency for CustomLabel references", "package": None, "description": "Custom Labels not referenced in code or Flows", "threshold": "AI assessment", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "9.7",  "name": "Unused Custom Permissions", "category": "technical_debt", "data_source": "ai_inference", "sf_cli_cmd": "sf data query on CustomPermission + SetupEntityAccess", "package": None, "description": "Custom Permissions not assigned to any Permission Set", "threshold": "AI assessment", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "9.8",  "name": "Unmanaged Package Sprawl", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT SubscriberPackage.Name FROM InstalledSubscriberPackage", "package": None, "description": "Number of unmanaged packages (hard to maintain)", "threshold": "0 unmanaged PASS, <5 WARN, >=5 FAIL", "assessable": True, "scoring_key": "installed_packages"},
    {"id": "9.9",  "name": "Managed Package Inventory", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT SubscriberPackage.Name, SubscriberPackageVersion.Name FROM InstalledSubscriberPackage", "package": None, "description": "Managed packages installed; check for unused or outdated", "threshold": "All current PASS, some outdated WARN", "assessable": True, "scoring_key": "installed_packages"},
    {"id": "9.10", "name": "AppExchange App Review", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "InstalledSubscriberPackage.SubscriberPackageVersion", "package": None, "description": "Installed apps still needed and on supported versions", "threshold": "AI assessment", "assessable": True, "scoring_key": "installed_packages"},
    {"id": "9.11", "name": "Visualforce to LWC Backlog", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT COUNT(Id) FROM ApexPage", "package": None, "description": "VF pages/components needing LWC migration", "threshold": "0 VF PASS, <10 WARN, >=10 FAIL", "assessable": True, "scoring_key": "vf_pages_detail"},
    {"id": "9.12", "name": "Classic to Lightning Gaps", "category": "technical_debt", "data_source": "ai_inference", "sf_cli_cmd": "Lightning Experience Readiness Check data", "package": None, "description": "Any remaining Classic-only configurations or pages", "threshold": "AI assessment", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "9.13", "name": "Sandbox Refresh Dates", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT SandboxName, LicenseType, LastModifiedDate FROM SandboxInfo", "package": None, "description": "Sandboxes not refreshed in 6+ months", "threshold": "All <6mo PASS, some >6mo WARN, many >6mo FAIL", "assessable": True, "scoring_key": "sandbox_info"},
    {"id": "9.14", "name": "Metadata Component Count", "category": "technical_debt", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata summary by type", "package": None, "description": "Total metadata components; high counts slow deployments", "threshold": "<5000 PASS, <10000 WARN, >=10000 FAIL", "assessable": True, "scoring_key": "metadata_total"},
    {"id": "9.15", "name": "Deployment Frequency", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT Status, StartDate FROM DeployRequest WHERE CreatedDate=LAST_N_DAYS:180", "package": None, "description": "How often deployments happen (CI/CD maturity)", "threshold": ">1/week PASS, >1/month WARN, <1/month FAIL", "assessable": True, "scoring_key": "deploy_requests"},
    {"id": "9.16", "name": "Failed Deployment Rate", "category": "technical_debt", "data_source": "tooling_api", "sf_cli_cmd": "SELECT Status FROM DeployRequest WHERE CreatedDate=LAST_N_DAYS:180", "package": None, "description": "% of deployments that fail", "threshold": "<10% PASS, <25% WARN, >=25% FAIL", "assessable": True, "scoring_key": "deploy_requests"},
    {"id": "9.17", "name": "Org-Specific Hardcoding", "category": "technical_debt", "data_source": "code_analysis", "sf_cli_cmd": "Regex scan of Apex source for URLs and org-specific patterns", "package": None, "description": "Environment-specific URLs, IDs, or credentials in code", "threshold": "0 found PASS, any FAIL", "assessable": True, "scoring_key": "hardcoded_ids"},
    {"id": "9.18", "name": "Custom Object Prefix Usage", "category": "technical_debt", "data_source": "metadata", "sf_cli_cmd": "sf org list metadata -m CustomObject, check naming", "package": None, "description": "Objects using proper namespace prefixes for manageability", "threshold": "AI assessment", "assessable": True, "scoring_key": "ai_inference"},
    {"id": "9.19", "name": "Technical Debt Score (Aggregate)", "category": "technical_debt", "data_source": "ai_inference", "sf_cli_cmd": "Composite calculation from all sub-metrics", "package": None, "description": "Weighted score combining all debt indicators above", "threshold": "Computed from sub-metrics", "assessable": True, "scoring_key": "ai_inference"},

