    {"id": "10.8",  "name": "Encryption at Rest", "category": "compliance", "data_source": "ai_inference", "sf_cli_cmd": "TenantSecret records, encrypted field identification", "package": None, "description": "Shield Platform Encryption or Classic Encryption enabled", "threshold": "Enabled PASS, not enabled WARN", "assessable": True, "scoring_key": "ai_inference"},
